onClick:
{{
(() => {

    // ==========================
    // VALIDAR CLAVE
    // ==========================

    if (
        qryANCFValidarClaveReversion.data?.[0]?.clave_valida !== 1
    ) {

        showAlert(
            "La clave de anulación es incorrecta.",
            "warning"
        );

        return;

    }

    // ==========================
    // VALIDAR MOTIVO
    // ==========================

    if (!inpMotivoReversionANCF.text?.trim()) {

        showAlert(
            "Debe indicar el motivo de la reversión.",
            "warning"
        );

        return;

    }

    // ==========================
    // REVERSAR
    // ==========================

    qryANCFReversar.run()

    .then(() => {

        closeModal("mdlReversionANCF");

        return Promise.all([

            inpClaveReversionANCF.setValue(""),

            inpMotivoReversionANCF.setValue(""),

            qryANCFConsultar.run()

        ]);

    })

    .then(() => {

        showAlert(
            "Aplicación reversada correctamente.",
            "success"
        );

    })

    .catch((e) => {

        showAlert(
            e.message,
            "error"
        );

    });

})();
}}
